func metricsMiddleware(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		start := time.Now()

		userID := r.URL.Query().Get("user_id")
		if userID == "" {
			userID = "anonymous"
		}

		requestID := r.URL.Query().Get("request_id")
		if requestID == "" {
			requestID = strconv.FormatInt(time.Now().UnixNano(), 10)
		}

		path := r.URL.Path
		method := r.Method

		requestsTotal.WithLabelValues(userID, path, method, requestID).Inc()
		activeUsers.WithLabelValues(userID).Set(1)

		next.ServeHTTP(w, r)

		requestDuration.WithLabelValues(userID, path, method, requestID).Observe(time.Since(start).Seconds())
	})
}

func trackHandler(w http.ResponseWriter, r *http.Request) {
	userID := r.URL.Query().Get("user_id")
	if userID == "" {
		userID = "anonymous"
	}

	requestID := r.URL.Query().Get("request_id")
	if requestID == "" {
		requestID = strconv.FormatInt(time.Now().UnixNano(), 10)
	}

	operation := r.URL.Query().Get("operation")
	if operation == "" {
		operation = "unknown"
	}

	userOperationsTotal.WithLabelValues(userID, operation, requestID).Inc()

	if r.URL.Query().Get("active") == "false" {
		activeUsers.WithLabelValues(userID).Set(0)
	} else {
		activeUsers.WithLabelValues(userID).Set(1)
	}

	w.WriteHeader(http.StatusOK)
	_, _ = w.Write([]byte("tracked\n"))
}

